                                            <div className="form-row"><div className="form-group"><label>Power Status</label><input type="text" name="power_status" value={displayEvent.power_status} onChange={handleInputChange} /></div><div className="form-group"><label>Remarks</label><input type="text" name="remark_power_status" value={displayEvent.remark_power_status || ''} onChange={handleInputChange} /></div></div>
                                            <div className="form-row"><div className="form-group"><label>Communication Lines</label><input type="text" name="communication_lines" value={displayEvent.communication_lines} onChange={handleInputChange} /></div><div className="form-group"><label>Remarks</label><input type="text" name="remark_communication_lines" value={displayEvent.remark_communication_lines || ''} onChange={handleInputChange} /></div></div>
                                            <div className="form-row"><div className="form-group"><label>Damage to Facilities</label><input type="text" name="damage_facilities" value={displayEvent.damage_facilities} onChange={handleInputChange} /></div><div className="form-group"><label>Remarks</label><input type="text" name="remark_damage_facilities" value={displayEvent.remark_damage_facilities || ''} onChange={handleInputChange} /></div></div>
                                            <div className="form-row"><div className="form-group checkbox-group"><label><input type="checkbox" name="work_suspension" checked={displayEvent.work_suspension} onChange={handleInputChange} /> Work Suspension</label></div><div className="form-group"><label>Remarks</label><input type="text" name="remark_work_suspension" value={displayEvent.remark_work_suspension || ''} onChange={handleInputChange} /></div></div>
                                            <div className="form-row"><div className="form-group"><label>Assistance Provided</label><input type="text" name="assistance_provided" value={displayEvent.assistance_provided} onChange={handleInputChange} /></div><div className="form-group"><label>Remarks</label><input type="text" name="remark_assistance_provided" value={displayEvent.remark_assistance_provided || ''} onChange={handleInputChange} /></div></div>
                                        </div>
                                    )}
                                </div>
                                <div className="edit-section">
                                    <div className="edit-section-header" onClick={() => toggleSection('remarks')}><h4>📝 General Remarks</h4><span>{expandedSections.remarks ? '▼' : '►'}</span></div>
                                    {expandedSections.remarks && (
                                        <div className="edit-section-content"><div className="form-group"><label>Overall Remarks</label><textarea name="remark" value={displayEvent.remark || ''} onChange={handleInputChange} rows="3" placeholder="Additional notes or instructions..." /></div></div>
